     1→import React, { useEffect, useState, useCallback } from "react";
     2→import { Center, Loader, Alert, Text, Table, Box, SegmentedControl, Group, Anchor, Button, Modal, Textarea, Select } from "@mantine/core";
     3→import { fetchSessions, fetchRepoStatuses, spawnSession, subscribeToUpdates, type Session, type RepoStatus } from "../api";
     4→import { SessionRow, COL_WIDTHS } from "../components/SessionRow";
     5→import { useBreadcrumb } from "../BreadcrumbContext";
     6→import { useTabs } from "../TabsContext";
     7→
     8→const SESSION_COLUMNS: { label: string; width: number }[] = [
     9→  { label: "Session ID",  width: COL_WIDTHS.sessionId      },
    10→  { label: "User",        width: COL_WIDTHS.user            },
    11→  { label: "Repo",        width: COL_WIDTHS.repo            },
    12→  { label: "Branch",      width: COL_WIDTHS.branch          },
    13→  { label: "Intent",      width: COL_WIDTHS.intent          },
    14→  { label: "Parent",      width: COL_WIDTHS.parentSessionId },
    15→  { label: "Started",     width: COL_WIDTHS.started         },
    16→  { label: "Updated",     width: COL_WIDTHS.updated         },
    17→];
    18→
    19→const REPO_COLUMNS = ["Repo", "User", "Branch"] as const;
    20→
    21→const SESSION_TOTAL_WIDTH = Object.values(COL_WIDTHS).reduce((a, b) => a + b, 0) + 16;
    22→
    23→export function ActiveSessions() {
    24→  const { openSessionTab, openBranchLogTab } = useTabs();
    25→  const [view, setView] = useState<"sessions" | "repos">("sessions");
    26→  const [sessions, setSessions] = useState<Session[]>([]);
    27→  const [repoStatuses, setRepoStatuses] = useState<RepoStatus[]>([]);
    28→  const [loading, setLoading] = useState(true);
    29→  const [error, setError] = useState<string | null>(null);
    30→  const { setCrumbs } = useBreadcrumb();
    31→
    32→  const [newSessionOpen, setNewSessionOpen] = useState(false);
    33→  const [newPrompt, setNewPrompt] = useState("");
    34→  const [newCwd, setNewCwd] = useState("");
    35→  const [spawning, setSpawning] = useState(false);
    36→  const [spawnError, setSpawnError] = useState<string | null>(null);
    37→
    38→  const load = useCallback(async () => {
    39→    try {
    40→      const [data, statuses] = await Promise.all([fetchSessions(), fetchRepoStatuses()]);
    41→      setSessions(data);
    42→      setRepoStatuses(statuses);
    43→      setError(null);
    44→      return data;
    45→    } catch (err) {
    46→      setError(String(err));
    47→      return [] as Session[];
    48→    }
    49→  }, []);
    50→
    51→  useEffect(() => {
    52→    load().then((data) => {
    53→      const first = data[0];
    54→      const user = first?.gitUserName ?? first?.gitUserEmail ?? null;
    55→      setCrumbs([
    56→        ...(user ? [{ label: user }] : []),
    57→      ]);
    58→    }).finally(() => setLoading(false));
    59→    return subscribeToUpdates(() => { load().catch(() => undefined); });
    60→  }, [load]);
    61→
    62→  async function handleSpawn() {
    63→    if (!newPrompt.trim()) return;
    64→    setSpawning(true);
    65→    setSpawnError(null);
    66→    try {
    67→      await spawnSession(newPrompt.trim(), newCwd || (repoStatuses[0]?.localPath ?? process.env.HOME ?? "/"));
    68→      setNewSessionOpen(false);
    69→      setNewPrompt("");
    70→    } catch (err) {
    71→      setSpawnError(String(err));
    72→    } finally {
    73→      setSpawning(false);
    74→    }
    75→  }
    76→
    77→  if (loading) {
    78→    return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
    79→  }
    80→
    81→  if (error) {
    82→    return (
    83→      <Center style={{ flex: 1, padding: 24 }}>
    84→        <Alert color="red" title="Cannot reach API server" maw={480}>
    85→          <Text size="sm" mb={4}>
    86→            Start the server with:{" "}
    87→            <Text component="span" ff="monospace" size="sm">claude-hook-handler serve</Text>
    88→          </Text>
    89→          <Text size="xs" c="dimmed">{error}</Text>
    90→        </Alert>
    91→      </Center>
    92→    );
    93→  }
    94→
    95→  const cwdOptions = repoStatuses.map((r) => ({ value: r.localPath, label: r.name ?? r.localPath }));
    96→
    97→  return (
    98→    <Box style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
    99→      <Modal
   100→        opened={newSessionOpen}
   101→        onClose={() => { setNewSessionOpen(false); setSpawnError(null); }}
   102→        title="New session"
   103→        size="md"
   104→      >
   105→        {cwdOptions.length > 0 && (
   106→          <Select
   107→            label="Working directory"
   108→            placeholder="Pick a repo…"
   109→            data={cwdOptions}
   110→            value={newCwd || null}
   111→            onChange={(v) => setNewCwd(v ?? "")}
   112→            mb="sm"
   113→            clearable
   114→          />
   115→        )}
   116→        <Textarea
   117→          label="Prompt"
   118→          placeholder="What should Claude do?"
   119→          autosize
   120→          minRows={4}
   121→          maxRows={12}
   122→          value={newPrompt}
   123→          onChange={(e) => setNewPrompt(e.currentTarget.value)}
   124→          onKeyDown={(e) => { if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handleSpawn(); }}
   125→          mb="sm"
   126→          data-autofocus
   127→        />
   128→        {spawnError && <Text size="xs" c="red" mb="sm">{spawnError}</Text>}
   129→        <Group justify="flex-end">
   130→          <Button variant="default" size="xs" onClick={() => setNewSessionOpen(false)}>Cancel</Button>
   131→          <Button size="xs" color="indigo" loading={spawning} disabled={!newPrompt.trim()} onClick={handleSpawn}>
   132→            Start session
   133→          </Button>
   134→        </Group>
   135→      </Modal>
   136→
   137→      <Group px={12} py={8} justify="space-between" style={{ borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))", flexShrink: 0 }}>
   138→        <SegmentedControl
   139→          size="xs"
   140→          value={view}
   141→          onChange={(v) => setView(v as "sessions" | "repos")}
   142→          data={[
   143→            { label: "Sessions", value: "sessions" },
   144→            { label: "Repos",    value: "repos"    },
   145→          ]}
   146→        />
   147→        <Button size="xs" color="indigo" onClick={() => { setNewSessionOpen(true); setSpawnError(null); }}>
   148→          New session
   149→        </Button>
   150→      </Group>
   151→
   152→      {view === "sessions" ? (
   153→        sessions.length === 0 ? (
   154→          <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No sessions yet.</Text></Center>
   155→        ) : (
   156→          <Box style={{ flex: 1, overflow: "hidden" }}>
   157→            <Table.ScrollContainer minWidth={SESSION_TOTAL_WIDTH} h="100%">
   158→              <Table stickyHeader highlightOnHover>
   159→                <Table.Thead>
   160→                  <Table.Tr>
   161→                    {SESSION_COLUMNS.map(({ label, width }) => (
   162→                      <Table.Th key={label} style={{ width, fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
   163→                        {label}
   164→                      </Table.Th>
   165→                    ))}
   166→                  </Table.Tr>
   167→                </Table.Thead>
   168→                <Table.Tbody>
   169→                  {sessions.map((item) => (
   170→                    <SessionRow
   171→                      key={item.sessionId}
   172→                      session={item}
   173→                      onPress={() =>
   174→                        openSessionTab(
   175→                          item.sessionId,
   176→                          item.summary ?? item.intent ?? item.sessionId.slice(0, 8) + "…",
   177→                        )
   178→                      }
   179→                    />
   180→                  ))}
   181→                </Table.Tbody>
   182→              </Table>
   183→            </Table.ScrollContainer>
   184→          </Box>
   185→        )
   186→      ) : (
   187→        repoStatuses.length === 0 ? (
   188→          <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No repos configured.</Text></Center>
   189→        ) : (
   190→          <Box style={{ flex: 1, overflow: "hidden" }}>
   191→            <Table.ScrollContainer minWidth={600} h="100%">
   192→              <Table stickyHeader highlightOnHover>
   193→                <Table.Thead>
   194→                  <Table.Tr>
   195→                    {REPO_COLUMNS.map((label) => (
   196→                      <Table.Th key={label} style={{ fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
   197→                        {label}
   198→                      </Table.Th>
   199→                    ))}
   200→                  </Table.Tr>
   201→                </Table.Thead>
   202→                <Table.Tbody>
   203→                  {repoStatuses.map((repo) => (
   204→                    <Table.Tr key={repo.localPath}>
   205→                      <Table.Td>
   206→                        {repo.currentBranch ? (
   207→                          <Anchor
   208→                            size="sm"
   209→                            fw={500}
   210→                            onClick={() =>
   211→                              openBranchLogTab(repo.localPath, repo.currentBranch!, repo.name)
   212→                            }
   213→                            style={{ cursor: "pointer" }}
   214→                            underline="never"
   215→                          >
   216→                            {repo.name}
   217→                          </Anchor>
   218→                        ) : (
   219→                          <Text size="sm" fw={500}>{repo.name}</Text>
   220→                        )}
   221→                      </Table.Td>
   222→                      <Table.Td>
   223→                        <Text size="sm" c="dimmed">{repo.gitUserName ?? repo.gitUserEmail ?? "—"}</Text>
   224→                      </Table.Td>
   225→                      <Table.Td>
   226→                        <Text size="sm" ff="monospace" c={repo.currentBranch ? "teal" : "dimmed"}>
   227→                          {repo.currentBranch ?? "—"}
   228→                        </Text>
   229→                      </Table.Td>
   230→                    </Table.Tr>
   231→                  ))}
   232→                </Table.Tbody>
   233→              </Table>
   234→            </Table.ScrollContainer>
   235→          </Box>
   236→        )
   237→      )}
   238→    </Box>
   239→  );
   240→}
   241→

