     1→import React, { createContext, useCallback, useContext, useRef, useState } from "react";
     2→
     3→export type Tab =
     4→  | { id: "home"; type: "home"; title: string }
     5→  | { id: string; type: "session"; sessionId: string; title: string; initialSearch?: string; initialState?: unknown }
     6→  | { id: string; type: "branchLog"; localPath: string; branch: string; repoName: string | null; title: string }
     7→  | { id: string; type: "launcher"; cwd: string; command: string; title: string };
     8→
     9→type NavigateFn = (to: string | number) => void;
    10→
    11→interface TabsContextValue {
    12→  tabs: Tab[];
    13→  activeTabId: string;
    14→  homePathname: string;
    15→  openSessionTab: (sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => void;
    16→  openBranchLogTab: (localPath: string, branch: string, repoName: string | null) => void;
    17→  closeTab: (id: string) => void;
    18→  setActiveTab: (id: string) => void;
    19→  updateTabTitle: (id: string, title: string) => void;
    20→  /** Navigate the home tab (and activate it). Accepts a path string or -1 for back. */
    21→  navigateHome: (to: string | number) => void;
    22→  /** Called by HomeTabRoutes to register its navigate function. */
    23→  registerHomeNavigate: (fn: NavigateFn | null) => void;
    24→  /** Called by HomeTabRoutes when location changes, to keep homePathname in sync. */
    25→  updateHomePathname: (pathname: string) => void;
    26→  openSessionWindow: (sessionId: string) => void;
    27→  openBranchLogWindow: (localPath: string, branch: string, repoName: string | null) => void;
    28→}
    29→
    30→const TabsContext = createContext<TabsContextValue | null>(null);
    31→
    32→const HOME_TAB: Tab = { id: "home", type: "home", title: "Sessions" };
    33→
    34→export function parseInitialTab(tabParam: string | null): Tab | null {
    35→  if (!tabParam) return null;
    36→  if (tabParam.startsWith("session:")) {
    37→    const sessionId = tabParam.slice("session:".length);
    38→    return { id: tabParam, type: "session", sessionId, title: sessionId.slice(0, 8) + "…" };
    39→  }
    40→  if (tabParam.startsWith("branchLog:")) {
    41→    const qs = tabParam.slice("branchLog:".length);
    42→    const p = new URLSearchParams(qs);
    43→    const localPath = p.get("localPath") ?? "";
    44→    const branch = p.get("branch") ?? "";
    45→    const repoName = p.get("repoName") ?? null;
    46→    const title = repoName ? `${repoName}/${branch}` : branch;
    47→    return { id: tabParam, type: "branchLog", localPath, branch, repoName, title };
    48→  }
    49→  return null;
    50→}
    51→
    52→export function TabsProvider({
    53→  children,
    54→  initialTab,
    55→}: {
    56→  children: React.ReactNode;
    57→  initialTab?: Tab | null;
    58→}) {
    59→  const startTabs: Tab[] = initialTab ? [HOME_TAB, initialTab] : [HOME_TAB];
    60→  const startActiveId = initialTab ? initialTab.id : "home";
    61→
    62→  const [tabs, setTabs] = useState<Tab[]>(startTabs);
    63→  const [activeTabId, setActiveTabId] = useState<string>(startActiveId);
    64→  const [homePathname, setHomePathname] = useState("/");
    65→  const homeNavigateRef = useRef<NavigateFn | null>(null);
    66→
    67→  const openSessionTab = useCallback((sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => {
    68→    const id = `session:${sessionId}`;
    69→    setTabs((prev) => {
    70→      if (prev.find((t) => t.id === id)) return prev;
    71→      return [...prev, { id, type: "session", sessionId, title, initialSearch, initialState }];
    72→    });
    73→    setActiveTabId(id);
    74→  }, []);
    75→
    76→  const openBranchLogTab = useCallback(
    77→    (localPath: string, branch: string, repoName: string | null) => {
    78→      const id = `branchLog:${localPath}:${branch}`;
    79→      setTabs((prev) => {
    80→        if (prev.find((t) => t.id === id)) return prev;
    81→        const title = repoName ? `${repoName}/${branch}` : branch;
    82→        return [...prev, { id, type: "branchLog", localPath, branch, repoName, title }];
    83→      });
    84→      setActiveTabId(id);
    85→    },
    86→    [],
    87→  );
    88→
    89→  const updateTabTitle = useCallback((id: string, title: string) => {
    90→    setTabs((prev) => prev.map((t) => (t.id === id ? { ...t, title } : t)));
    91→  }, []);
    92→
    93→  const closeTab = useCallback((id: string) => {
    94→    if (id === "home") return;
    95→    setTabs((prev) => {
    96→      const idx = prev.findIndex((t) => t.id === id);
    97→      const next = prev.filter((t) => t.id !== id);
    98→      setActiveTabId((current) => {
    99→        if (current !== id) return current;
   100→        if (next.length === 0) return "home";
   101→        return next[Math.max(0, idx - 1)].id;
   102→      });
   103→      return next;
   104→    });
   105→  }, []);
   106→
   107→  const navigateHome = useCallback((to: string | number) => {
   108→    setActiveTabId("home");
   109→    homeNavigateRef.current?.(to);
   110→    if (typeof to === "string") setHomePathname(to.split("?")[0]);
   111→  }, []);
   112→
   113→  const registerHomeNavigate = useCallback((fn: NavigateFn | null) => {
   114→    homeNavigateRef.current = fn;
   115→  }, []);
   116→
   117→  const updateHomePathname = useCallback((pathname: string) => {
   118→    setHomePathname(pathname);
   119→  }, []);
   120→
   121→  const openSessionWindow = useCallback((sessionId: string) => {
   122→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   123→    (window as any).electronAPI?.openWindow(`session:${sessionId}`);
   124→  }, []);
   125→
   126→  const openBranchLogWindow = useCallback(
   127→    (localPath: string, branch: string, repoName: string | null) => {
   128→      const params = new URLSearchParams({ localPath, branch, ...(repoName ? { repoName } : {}) });
   129→      // eslint-disable-next-line @typescript-eslint/no-explicit-any
   130→      (window as any).electronAPI?.openWindow(`branchLog:${params.toString()}`);
   131→    },
   132→    [],
   133→  );
   134→
   135→  return (
   136→    <TabsContext.Provider
   137→      value={{
   138→        tabs,
   139→        activeTabId,
   140→        homePathname,
   141→        openSessionTab,
   142→        openBranchLogTab,
   143→        closeTab,
   144→        setActiveTab: setActiveTabId,
   145→        updateTabTitle,
   146→        navigateHome,
   147→        registerHomeNavigate,
   148→        updateHomePathname,
   149→        openSessionWindow,
   150→        openBranchLogWindow,
   151→      }}
   152→    >
   153→      {children}
   154→    </TabsContext.Provider>
   155→  );
   156→}
   157→
   158→export function useTabs(): TabsContextValue {
   159→  const ctx = useContext(TabsContext);
   160→  if (!ctx) throw new Error("useTabs must be used within TabsProvider");
   161→  return ctx;
   162→}
