   428→  type V2Session = {
   429→    summary: {
   430→      intent: string; outcome: string;
   431→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   432→      frictionItems: { text: string }[];
   433→      repoLearnings: { text: string }[];
   434→      codeLearnings: { path: string; finding: string }[];
   435→      workflowLearnings: { text: string }[];
   436→    } | null;
   437→  };
   438→
   439→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   440→    return {
   441→      intent:            summary.intent,
   442→      outcome:           summary.outcome,
   443→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   444→      friction:          summary.frictionItems.map((r) => r.text),
   445→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   446→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   447→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   448→    };
   449→  }
   450→
   451→  const V2_SESSION_INCLUDE = {
   452→    summary: {
   453→      include: {
   454→        openItems:         true,
   455→        frictionItems:     true,
   456→        repoLearnings:     true,
   457→        codeLearnings:     true,
   458→        workflowLearnings: true,
   459→      },
   460→    },
   461→  } as const;
   462→
   463→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
