   465→  // GET /api/v2/checkpoints
   466→  app.get("/api/v2/checkpoints", async (_req, res) => {
   467→    try {
   468→      const checkpoints = await db.checkpointMetadata.findMany({
   469→        include: {
   470→          tokenUsage: true,
   471→          filesTouched: { include: { filePath: true } },
   472→        },
   473→      });
   474→
   475→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   476→
   477→      const sessions = await db.checkpointSessionMetadata.findMany({
   478→        where:   { checkpointId: { in: checkpointIds } },
   479→        orderBy: V2_SESSION_ORDER,
   480→        include: V2_SESSION_INCLUDE,
   481→      });
   482→
   483→      // Group sessions by checkpointId
   484→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   485→      for (const s of sessions) {
   486→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   487→        arr.push(s);
   488→        sessionsByCheckpoint.set(s.checkpointId, arr);
   489→      }
   490→
   491→      res.json(checkpoints.map((c) => {
   492→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   493→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   494→        const latestCreatedAt = cpSessions
   495→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   496→          .map((s) => s.createdAt)
   497→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   498→        return {
   499→          id:               c.id,
   500→          checkpointId:     c.checkpointId,
   501→          cliVersion:       c.cliVersion,
   502→          strategy:         c.strategy,
   503→          branch:           c.branch,
   504→          checkpointsCount: c.checkpointsCount,
   505→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   506→          tokenUsage: c.tokenUsage ? {
   507→            inputTokens:         c.tokenUsage.inputTokens,
   508→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   509→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   510→            outputTokens:        c.tokenUsage.outputTokens,
   511→            apiCallCount:        c.tokenUsage.apiCallCount,
   512→          } : null,
   513→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   514→          sessionCount:  cpSessions.length,
   515→          localPath:     repoDir ?? null,
   516→          summary: summary ? mapV2Summary(summary) : null,
   517→        };
   518→      }));
   519→    } catch (err) {
   520→      res.status(500).json({ error: String(err) });
   521→    }
   522→  });
