   658→  // GET /api/branch-log?localPath=<>&branch=<>
   659→  // Walks git log on the branch, parses "Entire-Checkpoint: <id>" trailers from
   660→  // commit bodies, then looks up each checkpoint in the DB individually.
   661→  app.get("/api/branch-log", async (req, res) => {
   662→    try {
   663→      const localPath = typeof req.query.localPath === "string" ? req.query.localPath : null;
   664→      const branch    = typeof req.query.branch    === "string" ? req.query.branch    : null;
   665→      if (!localPath || !branch) {
   666→        res.status(400).json({ error: "localPath and branch are required" });
   667→        return;
   668→      }
   669→
   670→      const page = typeof req.query.page === "string" ? Math.max(0, parseInt(req.query.page, 10) || 0) : 0;
   671→      const PAGE_SIZE = 50;
   672→
   673→      const repo = findRepo(localPath);
   674→      if (!repo) { res.status(404).json({ error: "Repo not found in config" }); return; }
   675→
   676→      const repoDb = repo.dbPath === dbPath ? db : await getDb(repo.dbPath);
   677→
   678→      // Walk git log and collect checkpoint IDs in commit order
   679→      const orderedIds: string[] = [];
   680→      const commitMessages = new Map<string, string>();
   681→      const commitHashes   = new Map<string, string>();
   682→      const seenIds = new Set<string>();
   683→      try {
   684→        const { stdout: gitOut } = await exec(
   685→          `git -C ${JSON.stringify(localPath)} log --format=%H%x00%B%x1e --max-count=${PAGE_SIZE} --skip=${page * PAGE_SIZE} ${JSON.stringify(branch)}`,
   686→          { timeout: 10_000 },
   687→        );
   688→        for (const record of gitOut.split("\x1e")) {
   689→          const nullIdx = record.indexOf("\x00");
   690→          if (nullIdx === -1) continue;
   691→          const hash = record.slice(0, nullIdx).trim();
   692→          const body = record.slice(nullIdx + 1);
   693→          const match = body.match(/^Entire-Checkpoint:\s*(\S+)$/m);
   694→          if (match && !seenIds.has(match[1])) {
   695→            seenIds.add(match[1]);
   696→            orderedIds.push(match[1]);
   697→            if (hash) commitHashes.set(match[1], hash);
   698→            // Commit message = body with trailer line(s) removed, trimmed
   699→            const message = body
   700→              .split("\n")
   701→              .filter((l) => !/^Entire-Checkpoint:\s*\S+$/.test(l.trim()))
   702→              .join("\n")
   703→              .trim();
   704→            if (message) commitMessages.set(match[1], message);
   705→          }
   706→        }
   707→      } catch { /* git unavailable or branch not found */ }
   708→
   709→      const result = [];
   710→      for (const checkpointId of orderedIds) {
   711→        const [sessions, cpMeta] = await Promise.all([
   712→          repoDb.checkpointSessionMetadata.findMany({
   713→            where:   { checkpointId },
   714→            orderBy: { createdAt: "asc" },
   715→            include: { ...V2_SESSION_INCLUDE, tokenUsage: true, filesTouched: { include: { filePath: true } } },
   716→          }),
   717→          repoDb.checkpointMetadata.findUnique({
   718→            where:  { checkpointId },
   719→            select: { gitUserName: true, gitUserEmail: true },
   720→          }),
   721→        ]);
   722→        for (const s of sessions) {
   723→          const hasEvents = await repoDb.logEvent.findFirst({
   724→            where: {
   725→              sessionId: s.sessionId,
   726→              sessionLink: { checkpointMetadata: { checkpointId: s.checkpointId } },
   727→            },
   728→            select: { id: true },
   729→          });
   730→          if (!hasEvents) continue;
   731→          result.push({
   732→            checkpointId:  s.checkpointId,
   733→            sessionId:     s.sessionId,
   734→            branch:        s.branch,
   735→            createdAt:     s.createdAt?.toISOString() ?? null,
   736→            gitUserName:   cpMeta?.gitUserName  ?? null,
   737→            gitUserEmail:  cpMeta?.gitUserEmail ?? null,
   738→            filesTouched:  s.filesTouched.map((f) => f.filePath.path),
   739→            tokenUsage:   s.tokenUsage ? {
   740→              inputTokens:         s.tokenUsage.inputTokens,
   741→              cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   742→              cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   743→              outputTokens:        s.tokenUsage.outputTokens,
   744→              apiCallCount:        s.tokenUsage.apiCallCount,
   745→            } : null,
   746→            summary:       s.summary ? mapV2Summary(s.summary) : null,
   747→            commitMessage: commitMessages.get(s.checkpointId) ?? null,
   748→            commitHash:    commitHashes.get(s.checkpointId)   ?? null,
   749→          });
   750→        }
   751→      }
   752→
   753→      // Find the live (shadow) session on this branch, if any
   754→      const liveShadow = await repoDb.shadowSession.findFirst({
