  1130→          `git -C ${JSON.stringify(localPath)} worktree add ${JSON.stringify(worktreePath)} ${CHECKPOINT_BRANCH}`,
  1131→          { stdio: "pipe" },
  1132→        );
  1133→        process.stderr.write(`checkpoint indexer: worktree created at ${worktreePath}\n`);
  1134→      } catch (err) {
