      const sessionRows = await db.checkpointSessionMetadata.findMany({
        where:   { sessionId },
        orderBy: { createdAt: "asc" },
        include: {
          ...V2_SESSION_INCLUDE,
          tokenUsage:   true,
          filesTouched: { include: { filePath: true } },
